+        let (pager, _) = wal_pager();
+        let cx = Cx::new();
+        let ps = PageSize::DEFAULT.as_usize();
+        let mut txn = pager.begin(&cx, TransactionMode::Concurrent).unwrap();
+        let first_page = txn.allocate_page(&cx).unwrap();
